/**
 * Initialize blog history tracking
 */
function initHistory() {
  if (!fs.existsSync(CONFIG.dataDir)) {
    fs.mkdirSync(CONFIG.dataDir, { recursive: true });
    logger.info('Created blogs-history directory');
  }
  
  let history = {};
  const historyFile = CONFIG.historyFile;
  
  // Initialize new history file with metadata
  if (!fs.existsSync(historyFile)) {
    history = {
      version: '2.0',
      createdAt: new Date().toISOString(),
      totalCreated: 0,
      lastTopic: null,
      lastDate: null,
      todayCount: 0,
      blogs: {}
    };
    fs.writeFileSync(historyFile, JSON.stringify(history, null, 2));
    logger.info('Initialized blog_history.json');
  } else {
    const content = fs.readFileSync(historyFile, 'utf8');
    history = JSON.parse(content);
  }
  
  return history;
}

/**
 * Save updated history
 */
function saveHistory(updates) {
  const history = initHistory();
  Object.assign(history, updates);
  
  // Persist every 5 blogs to avoid excessive writes
  if (history.totalCreated % 5 === 0) {
    fs.writeFileSync(CONFIG.historyFile, JSON.stringify(history, null, 2));
  }
}

/**
 * Get current blog count for today
 */
function getTodayCount() {
  const history = initHistory();
  return history.todayCount || 0;
}

