/**
 * Fetch from a specific model endpoint
 */
async function fetchFromModel(modelName, url, prompt) {
  const timeout = setTimeout(() => {
    logger.warn(`Request timed out for ${modelName}`);
  }, 60000); // 60 second timeout per request
  
  try {
    const response = await fetch(url, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${process.env.HERMES_API_KEY || ''}`,
        ...(modelName.includes('openai') ? { 'HTTP-Referer': 'https://govindtank.github.io' } : {}),
      },
      body: JSON.stringify({
        model: modelName,
        messages: [{ role: 'user', content: prompt }]
      })
    });
    
    clearTimeout(timeout);
    
    if (!response.ok) {
      throw new Error(`HTTP ${response.status}: ${response.statusText}`);
    }
    
    const data = await response.json();
    return data.choices[0].message.content;
    
  } catch (error) {
    clearTimeout(timeout);
    throw error;
  }
}

/**
 * Attempt to generate content with intelligent model failover
 */
async function generateContentWithFailover(prompt) {
  const allModels = [CONFIG.primaryModel, ...CONFIG.fallbackModels];
  
  logger.info(`🔍 Starting content generation with ${allModels.length} available models`);
  
  for (const modelName of allModels) {
    FAILED_ATTEMPTS++;
    
    if (FAILED_ATTEMPTS > MAX_FAILED_ATTEMPTS * allModels.length) {
      throw new Error('All model attempts exhausted');
    }
    
    logger.info(`🎯 Trying: ${modelName}`);
    
    try {
      // Skip local models for API requests, use OpenRouter fallback
      const isLocal = modelName.includes('localhost') || modelName === CONFIG.primaryModel;
      
      if (isLocal) {
        // Try local first
        logger.info(`  → Using local endpoint: ${CONFIG.primaryUrl}`);
        const response = await fetchFromModel(modelName, `${CONFIG.primaryUrl}/v1/chat/completions`, prompt);
        
        if (response && response.length > CONFIG.minWordCount) {
          logger.success(`Local model responded successfully!`);
          return { success: true, content: response };
        } else {
          logger.warn(`Local model response too short (${response?.length || 0} words), trying fallback...`);
        }
      }
      
      // If local fails or is unavailable, use OpenRouter as backup
      logger.info('  → Local failed/timeout, using OpenRouter fallback');
      
      const openrouterResponse = await fetch('https://openrouter.ai/api/v1/chat/completions', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${process.env.OPENROUTER_API_KEY}`,
          'HTTP-Referer': 'https://govindtank.github.io'
        },
        body: JSON.stringify({
          model: modelName.startsWith('openai/') ? 'openai/gpt-4o-mini' : 'mistralai/mistral-7b-instruct-v01',
          messages: [{ role: 'user', content: prompt }]
        })
      });
      
      if (!openrouterResponse.ok) {
        throw new Error(`OpenRouter error: ${openrouterResponse.status}`);
      }
      
      const openrouterData = await openrouterResponse.json();
      logger.success(`✅ OpenRouter fallback successful!`);
      
      return { 
        success: true, 
        content: openrouterData.choices[0].message.content 
      };
      
    } catch (error) {
      if (FAILED_ATTEMPTS < MAX_FAILED_ATTEMPTS * allModels.length) {
        const modelIndex = allModels.indexOf(modelName);
        logger.warn(`  → ${modelName} failed (${error.message}), trying next model...`);
        
        // Small delay before trying next model
        await new Promise(resolve => setTimeout(resolve, 2000));
      } else {
        throw new Error(`All ${allModels.length} models exhausted: ${error.message}`);
      }
    }
  }
  
  throw new Error('Model failover system failed completely');
}

