/**
 * Fetch latest news about a topic (using NewsAPI or similar)
 */
async function fetchNews(topic) {
  try {
    const apiKey = process.env.NEWS_API_KEY || 'demo';
    const searchQuery = encodeURIComponent(`${topic} development trends best practices`);
    
    const response = await fetch(
      `https://newsapi.org/v2/everything?q=${searchQuery}&sortBy=publishedAt&language=en&apiKey=${apiKey}`
    );
    
    if (!response.ok) {
      return generateNewsMock(topic); // Fallback to mock data
    }
    
    const data = await response.json();
    
    // Filter quality articles
    const qualityArticles = data.articles.filter(article => {
      const hasImage = article.urlToImage && !article.urlToImage.startsWith('i.');
      return article.title?.length > 20 && hasImage;
    }).slice(0, 5); // Top 5 articles
    
    return qualityArticles.length > 0 ? qualityArticles : generateNewsMock(topic);
    
  } catch (error) {
    logger.warn(`News API failed: ${error.message}`);
    return generateNewsMock(topic);
  }
}

