/**
 * Generate blog content using available models
 */
async function generateBlogContent(topic, newsArticles) {
  const prompt = createGenerationPrompt(topic, newsArticles);
  
  logger.info(`📝 Generating blog: "${topic}"`);
  
  try {
    // Try local Qwen model first
    const response = await generateContentWithFailover(prompt);
    
    if (!response.success) {
      throw new Error('Failed to generate content');
    }
    
    // Clean up and parse the response
    let content = response.content;
    
    // Remove any markdown code block wrappers
    content = content.replace(/^```(?:\w+)?\n/, '').replace(/\n```$/, '');
    
    // Check word count
    const wordCount = content.split(/[\s\n]+/).filter(w => w.length > 0).length;
    logger.info(`📊 Word count: ${wordCount}`);
    
    if (wordCount < CONFIG.minWordCount) {
      throw new Error(`Content too short: ${wordCount} words (min: ${CONFIG.minWordCount})`);
    }
    
    return { 
      title: extractTitle(content), 
      content, 
      newsArticles,
      topic,
      date: new Date()
    };
    
  } catch (error) {
    logger.error(`Content generation failed: ${error.message}`);
    throw error;
  }
}

/**
 * Extract title from markdown content
 */
function extractTitle(content) {
  const match = content.match(/^#(?:\s+([^\n]+))?/m);
  if (match && match[1]) {
    return match[1].trim();
  }
  return topic || 'Technical Insights'; // fallback to topic
}

/**
 * ============================================
 * BLOG ENTRY CREATION
 * ============================================
 */

/**
 * Create BlogPost entry for constants.ts
 */
function createBlogEntry(topic, title, content) {
  const slug = title.toLowerCase()
    .replace(/[^a-z0-9]/g, '-')
    .replace(/-+/g, '-')
    .substring(0, 50); // Keep slug reasonable length
  
  const dateObj = new Date();
  const formattedDate = dateObj.toLocaleDateString('en-US', {
    month: 'short',
    day: 'numeric',
    year: 'numeric'
  });
  
  const excerpt = content
    .match(/^#\s+\w+/m) // Skip title
    .join('\n')         // First paragraph after title
    ?.trim()
    .substring(0, 250);
  
  return {
    title,
    excerpt: excerpt || `A deep dive into ${topic} with practical examples and architectural insights.`,
    date: formattedDate,
    tag: determineTag(topic),
    slug,
    content // Full markdown for modal display
  };
}

/**
 * Determine appropriate category tag
 */
function determineTag(topic) {
  const topicLower = topic.toLowerCase();
  
  if (topicLower.includes('ai') || topicLower.includes('llm') || topicLower.includes('agent')) 
    return 'AI';
  if (topicLower.includes('flutter') || topicLower.includes('mobile') || topicLower.includes('android')) 
    return 'Mobile';
  if (topicLower.includes('architecture') || topicLower.includes('design') || topicLower.includes('patterns')) 
    return 'Architecture';
  if (topicLower.includes('api') || topicLower.includes('backend') || topicLower.includes('cloud')) 
    return 'Backend';
  
  const tags = ['DevOps', 'Security', 'Web3', 'Testing', 'Performance'];
  return tags[Math.floor(Math.random() * tags.length)];
}

