/**
 * Execute shell commands safely
 */
async function runGitCommand(command, description) {
  const child = spawn.sync('sh', ['-c', command], {
    stdio: ['pipe', 'pipe', 'pipe'],
    cwd: CONFIG.repoRoot,
    env: { ...process.env, GIT_USER_NAME: CONFIG.gitUser, GIT_USER_EMAIL: CONFIG.gitEmail }
  });
  
  const output = child.stdout.toString();
  const errorOutput = child.stderr.toString();
  
  if (child.status !== 0) {
    throw new Error(`${description} failed:\n${errorOutput || 'Unknown error'}`);
  }
  
  logger.info(`✓ ${description}`);
  return output;
}

/**
 * Commit and push changes to GitHub
 */
async function commitAndPush() {
  setupGitHubRemote();
  
  const commands = [
    `git config --global user.name "${CONFIG.gitUser}"`,
    `git config --global user.email "${CONFIG.gitEmail}"`,
    'git add src/constants.ts data/blogs-history/blog_history.json',
    'git commit -m "chore: auto-publish blog post about trending topic" --no-gpg-sign',
    'git push origin main'
  ];
  
  for (const cmd of commands) {
    await runGitCommand(cmd, cmd.replace('git ', ''));
  }
}

